import React, { createContext, useEffect, useMemo, useState } from 'react';
import { StyleSheet, View } from 'react-native';
import AppNavigator from './src/navigation/AppNavigator';
import LoadingScreen from './src/screens/LoadingScreen';
import { onAuthStateChangedListener, getUserProfile, signOutUser } from './src/services/firebaseService';
import { User as FirebaseUser } from 'firebase/auth';

export type UserProfile = {
  uid: string;
  name: string;
  email: string;
  phone: string;
  address?: string;
  role: 'customer' | 'owner';
  approved: boolean;
};

export type AuthContextType = {
  user: FirebaseUser | null;
  profile: UserProfile | null;
  initializing: boolean;
  refreshProfile: () => Promise<void>;
  signOut: () => Promise<void>;
};

export const AuthContext = createContext<AuthContextType>({
  user: null,
  profile: null,
  initializing: true,
  refreshProfile: async () => {},
  signOut: async () => {}
});

export default function App() {
  const [user, setUser] = useState<FirebaseUser | null>(null);
  const [profile, setProfile] = useState<UserProfile | null>(null);
  const [initializing, setInitializing] = useState(true);

  const refreshProfile = async () => {
    if (!user) {
      setProfile(null);
      return;
    }
    try {
      const profileData = await getUserProfile(user.uid);
      setProfile(profileData);
    } catch (error) {
      console.error('Failed to refresh profile', error);
      setProfile(null);
    }
  };

  const signOut = async () => {
    await signOutUser();
  };

  useEffect(() => {
    const unsubscribe = onAuthStateChangedListener(async (authUser) => {
      setInitializing(true);
      setUser(authUser);
      if (!authUser) {
        setProfile(null);
        setInitializing(false);
        return;
      }

      try {
        const profileData = await getUserProfile(authUser.uid);
        setProfile(profileData);
      } catch (error) {
        console.error('Failed to load user profile during app startup', error);
        setProfile(null);
      } finally {
        setInitializing(false);
      }
    });
    return unsubscribe;
  }, []);

  const authContextValue = useMemo(
    () => ({ user, profile, initializing, refreshProfile, signOut }),
    [user, profile, initializing]
  );

  if (initializing) {
    return <LoadingScreen />;
  }

  return (
    <AuthContext.Provider value={authContextValue}>
      <View style={styles.container}>
        <AppNavigator />
      </View>
    </AuthContext.Provider>
  );
}

const styles = StyleSheet.create({
  container: {
    flex: 1
  }
});
